module RefModule (  
    input clk,  
    input reset,  
    input enable,  
    output reg [2:0] active_channel  
);  

    reg [2:0] obf_channel;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            obf_channel <= 3'b000;  
            active_channel <= 3'b000;  
        end else if (enable) begin  
            if (obf_channel < 3'b111)  
                obf_channel <= obf_channel + 1;  
            else  
                obf_channel <= 3'b000;  
            active_channel <= obf_channel;  
        end  
    end  
endmodule
